#!/usr/bin/env node
import fs from 'node:fs';
import path from 'node:path';
import crypto from 'node:crypto';
const root = process.cwd();
const cfg = JSON.parse(fs.readFileSync(path.join(root,'config/holy-grail-browser-demo.json'),'utf8'));
const out = path.join(root,'artifacts/holy-grail-proof-run-001');
fs.rmSync(out,{recursive:true,force:true}); fs.mkdirSync(out,{recursive:true});
const h = v => crypto.createHash('sha256').update(JSON.stringify(v)).digest('hex');
const mission = { id:'HG-PR001-DEMO', objective:'Public-safe proof-gated work-machine demo', dataBoundary:'synthetic demo only; no user data', loop:cfg.loop, contact:cfg.contactEmail };
const claims = cfg.scenarios.map(s => ({ scenario:s.id, claim:s.claim, evidence:`evidence://${s.id}/demo`, status:'demo-supported' }));
const docket = { id:'ED-HG-PR001-DEMO', manifest:mission, claimsMatrix:claims, proofPackets:cfg.loop.map((x,i)=>({stage:x,digest:h([x,i]).slice(0,16)})), riskLedger:['no uploads','no sign-in','no wallet','no cookies','no analytics','no value moved'], replayPath:'Open proof-run-001.html and click Launch proof loop.' };
const verifier = { verdict:'review-ready demo', checks:['mission exists','claims matrix exists','proof packets exist','risk ledger exists','receipt exists'], limitations:['synthetic demo','not external audit','not live settlement'] };
const chronicle = { event:'Holy Grail candidate proof loop demonstrated', reusableCapability:'Proof-to-acceptance mission template', nextMission:'First public-safe Proof Run 001 with external review' };
const capability = { id:'CAP-HG-001', name:'Proof-gated work-machine narrative and demo', initiation:'AI work needs evidence-backed acceptance', termination:'review-ready receipt exists' };
const settlement = { type:'readiness-signal', tokenReference:cfg.externalToken, valueMoved:false, walletConnected:false };
const receipt = { id:'MR-HG-PR001-DEMO', decision:'review-ready', evidenceDocketHash:h(docket), verifierReportHash:h(verifier), noValueMoved:true, issuedAt:new Date().toISOString() };
const files = { 'mission-contract.json':mission, 'claims-matrix.json':claims, 'evidence-docket.json':docket, 'verifier-report.json':verifier, 'chronicle-entry.json':chronicle, 'capability-package.json':capability, 'settlement-signal.json':settlement, 'mission-receipt.json':receipt };
for(const [name,data] of Object.entries(files)) fs.writeFileSync(path.join(out,name), JSON.stringify(data,null,2));
fs.writeFileSync(path.join(out,'README.md'), `# GoalOS Holy Grail Proof Run 001 demo\n\nPublic-safe synthetic artifact bundle. No user data. No value moved.\n\nOpen the generated website page \`proof-run-001.html\` and run the browser-local proof loop.\n`);
console.log('Generated Holy Grail Proof Run 001 demo artifact at '+out);
